import{_ as a,o as i,c as o,a2 as s}from"./chunks/framework.DCVnL8g5.js";const g=JSON.parse('{"title":"Fundamentos Básicos de Git","description":"","frontmatter":{},"headers":[],"relativePath":"herramientas/git/01-fundamentos-basicos.md","filePath":"herramientas/git/01-fundamentos-basicos.md","lastUpdated":1782521464000}'),n={name:"herramientas/git/01-fundamentos-basicos.md"};function t(r,e,l,c,d,p){return i(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="fundamentos-basicos-de-git" tabindex="-1">Fundamentos Básicos de Git <a class="header-anchor" href="#fundamentos-basicos-de-git" aria-label="Permalink to &quot;Fundamentos Básicos de Git&quot;">​</a></h1><h2 id="introduccion-a-la-gestion-de-versiones-y-git" tabindex="-1">Introducción a la gestión de versiones y Git <a class="header-anchor" href="#introduccion-a-la-gestion-de-versiones-y-git" aria-label="Permalink to &quot;Introducción a la gestión de versiones y Git&quot;">​</a></h2><p>La gestión de versiones es una práctica esencial en el desarrollo de software que permite rastrear y controlar los cambios en el código fuente y otros recursos del proyecto. Git es un sistema de control de versiones distribuido ampliamente utilizado en la industria.</p><p><strong>Zona Clave</strong>: Comprender la importancia de la gestión de versiones, control de versiones centralizado vs. distribuido y la función de Git en el control de versiones.</p><h2 id="instalacion-de-git-en-tu-sistema" tabindex="-1">Instalación de Git en tu sistema <a class="header-anchor" href="#instalacion-de-git-en-tu-sistema" aria-label="Permalink to &quot;Instalación de Git en tu sistema&quot;">​</a></h2><p>Antes de comenzar a utilizar Git, debes instalarlo en tu sistema operativo. Git es compatible con Windows, macOS y Linux. A continuación, se detallan los pasos para la instalación en los sistemas operativos más comunes:</p><p><strong>Windows</strong>:</p><ol><li>Descarga el instalador de Git desde <a href="https://git-scm.com/download/win" target="_blank" rel="noreferrer">https://git-scm.com/download/win</a>.</li><li>Ejecuta el instalador y sigue las instrucciones.</li></ol><p><strong>macOS</strong>:</p><ol><li>Puedes instalar Git a través de Xcode Command Line Tools o utilizando Homebrew.</li><li>Si usas Homebrew, ejecuta el comando <code>brew install git</code>.</li></ol><p><strong>Linux</strong>:</p><ol><li>En distribuciones basadas en Debian (como Ubuntu), ejecuta <code>sudo apt-get install git</code>.</li><li>En distribuciones basadas en Red Hat (como CentOS), ejecuta <code>sudo yum install git</code>.</li></ol><p><strong>Zona Clave</strong>: Aprender a instalar Git en tu sistema operativo específico y verificar la instalación con <code>git --version</code>.</p><h2 id="configuracion-inicial-de-git" tabindex="-1">Configuración inicial de Git <a class="header-anchor" href="#configuracion-inicial-de-git" aria-label="Permalink to &quot;Configuración inicial de Git&quot;">​</a></h2><p>Después de instalar Git, es importante configurar tu nombre de usuario y dirección de correo electrónico. Estas configuraciones se utilizan para identificarte en los commits que realices en tus proyectos.</p><p><strong>Configuración Global</strong>: Ejecuta los siguientes comandos en tu terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user.name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Tu Nombre&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user.email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;tu@email.com&quot;</span></span></code></pre></div><p><strong>Zona Clave</strong>: Configurar la identidad de Git con <code>git config --global</code>, que se aplica a todos los proyectos Git en tu sistema.</p><h2 id="inicializacion-de-un-repositorio-git-local" tabindex="-1">Inicialización de un repositorio Git local <a class="header-anchor" href="#inicializacion-de-un-repositorio-git-local" aria-label="Permalink to &quot;Inicialización de un repositorio Git local&quot;">​</a></h2><p>Un repositorio Git (repo) es una ubicación donde Git almacena datos y registros de cambios. Puedes iniciar un repositorio Git en tu proyecto existente o comenzar uno desde cero.</p><p><strong>Creación de un Repositorio Nuevo</strong>:</p><ol><li>Navega hasta el directorio raíz de tu proyecto en la terminal.</li><li>Ejecuta el comando <code>git init</code> para crear un nuevo repositorio.</li></ol><p><strong>Zona Clave</strong>: Iniciar un repositorio con <code>git init</code> y comprender la diferencia entre el área de trabajo, el repositorio local y el repositorio remoto.</p><h2 id="comandos-basicos-de-git" tabindex="-1">Comandos básicos de Git <a class="header-anchor" href="#comandos-basicos-de-git" aria-label="Permalink to &quot;Comandos básicos de Git&quot;">​</a></h2><p>Git ofrece una serie de comandos básicos para interactuar con el repositorio. Aquí se describen algunos de los comandos fundamentales:</p><ul><li><code>git add</code>: Agrega cambios de tu área de trabajo al área de preparación (staging).</li><li><code>git commit</code>: Guarda los cambios en el área de preparación en el repositorio.</li><li><code>git status</code>: Muestra el estado actual de los archivos en tu repositorio.</li><li><code>git log</code>: Muestra un registro de todos los commits en el repositorio.</li></ul><p><strong>Zona Clave</strong>: Comprender los conceptos de control de versiones, el área de trabajo, el área de preparación y el repositorio local. Usar <code>git add</code> y <code>git commit</code>.</p><h2 id="creacion-y-gestion-de-ramas-branch-en-git" tabindex="-1">Creación y gestión de ramas (branch) en Git <a class="header-anchor" href="#creacion-y-gestion-de-ramas-branch-en-git" aria-label="Permalink to &quot;Creación y gestión de ramas (branch) en Git&quot;">​</a></h2><p>Las ramas son líneas de desarrollo independientes en Git. Aprende a crear y gestionar ramas para trabajar en paralelo y realizar cambios experimentales sin afectar la rama principal.</p><p><strong>Creación de una Rama Nueva</strong>:</p><ol><li>Ejecuta el comando <code>git branch nombre_de_rama</code> para crear una nueva rama.</li><li>Utiliza <code>git checkout nombre_de_rama</code> para cambiar a la nueva rama.</li></ol><p><strong>Zona Clave</strong>: Comprender las ramas y cómo crear, cambiar y fusionar con <code>git branch</code>, <code>git checkout</code> y <code>git merge</code>.</p><h2 id="inicializacion-de-un-repositorio-git-local-1" tabindex="-1">Inicialización de un repositorio Git local <a class="header-anchor" href="#inicializacion-de-un-repositorio-git-local-1" aria-label="Permalink to &quot;Inicialización de un repositorio Git local&quot;">​</a></h2><p>Supongamos que tienes un proyecto web y deseas iniciar un repositorio Git en él. Sigue estos pasos:</p><ol><li><p><strong>Instala Git en tu sistema</strong> si aún no lo has hecho según las instrucciones para tu sistema operativo.</p></li><li><p>Abre una <strong>terminal</strong> y navega hasta el <strong>directorio raíz de tu proyecto</strong>.</p></li><li><p>Inicia un nuevo <strong>repositorio Git</strong> con el comando <code>git init</code>.</p></li></ol>`,35)])])}const m=a(n,[["render",t]]);export{g as __pageData,m as default};
